#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt,cost;
}e[200010];
long long head[200010],tot=1,res;
long long n,m,s,t,d[200010],now[200010],p[5050][5050];
bool vis[200010];
void add1(long long u,long long v,long long w,long long c)
{
    e[++tot]=(edge){v,w,head[u],c};
    head[u]=tot;
}
void add(long long u,long long v,long long w,long long c)
{
    add1(u,v,w,c);
    add1(v,u,0,-c);
}
bool spfa()
{
    memset(d,0x3f,sizeof(d));
    long long tmp=d[0];
    queue<long long> q;
    q.push(s);
    d[s]=0;
    while(!q.empty())
    {
        int t=q.front();
        q.pop();
        vis[t]=false;
        for(int i=head[t];i;i=e[i].nxt)
        {
            int v=e[i].to,cost=e[i].cost;
            if(e[i].val&&d[v]>d[t]+cost)
            {
                d[v]=d[t]+cost;
                if(!vis[v])
                {
                    vis[v]=true;
                    q.push(v);
                }
            }
        }
    }
    return d[t]<tmp;
}
long long dfs(long long x,long long flow)
{
    if(x==t)
    {
        return flow;
    }
    vis[x]=true;
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val,cost=e[i].cost;
        if(!vis[v]&&d[v]==d[x]+cost&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            res+=tmp*cost;
            flow-=tmp;
        }
    }
    vis[x]=false;
    return sum;
}
long long dinic()
{
    res=0;
    long long ans=0;
    while(spfa())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,INT_MAX);
    }
    return ans;
}
long long val[5050][5050],id;
void clear()
{
    memset(head,0,sizeof(head));
    memset(e,0,sizeof(e));
    tot=1;
}
int nxt(int x)
{
    return x+id;
}
void solve1()
{
    clear();
    s=0;
    t=id*2+1;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m+i-1;j++)
        {
            add(p[i][j],nxt(p[i][j]),1,-val[i][j]);
            if(p[i+1][j+1])
            {
                add(nxt(p[i][j]),p[i+1][j+1],1,0);
            }
            if(p[i+1][j])
            {
                add(nxt(p[i][j]),p[i+1][j],1,0);
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        add(s,p[1][i],1,0);
    }
    for(int i=1;i<=n+m-1;i++)
    {
        add(nxt(p[n][i]),t,1,0);
    }
    dinic();
    printf("%lld\n",-res);
}
void solve2()
{
    clear();
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m+i-1;j++)
        {
            if(p[i+1][j+1])
            {
                add(p[i][j],p[i+1][j+1],1,-val[i][j]);
            }
            if(p[i+1][j])
            {
                add(p[i][j],p[i+1][j],1,-val[i][j]);
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        add(s,p[1][i],1,0);
    }
    for(int i=1;i<=n+m-1;i++)
    {
        add(p[n][i],t,2e9,-val[n][i]);
    }
    dinic();
    printf("%lld\n",-res);
}
void solve3()
{
    clear();
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m+i-1;j++)
        {
            if(p[i+1][j+1])
            {
                add(p[i][j],p[i+1][j+1],2e9,-val[i][j]);
            }
            if(p[i+1][j])
            {
                add(p[i][j],p[i+1][j],2e9,-val[i][j]);
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        add(s,p[1][i],1,0);
    }
    for(int i=1;i<=n+m-1;i++)
    {
        add(p[n][i],t,2e9,-val[n][i]);
    }
    dinic();
    printf("%lld\n",-res);
}
int main()
{
    scanf("%lld%lld",&m,&n);
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m+i-1;j++)
        {
            scanf("%lld",&val[i][j]);
            p[i][j]=++id;
        }
    }
    solve1();
    solve2();
    solve3();
    return 0;
}
